INSERT INTO `exam_items` (`id`, `vacancy_id`, `question`, `is_essay`, `essay_max_score`, `choices`, `ans`, `created_at`, `updated_at`) VALUES
(1, 'ISAI(2-003', 'What does CPU stand for?', 0, NULL, '{\"A\": \"Central Processing Unit\", \"B\": \"Computer Power Unit\", \"C\": \"Central Program Utility\", \"D\": \"Control Processing Utility\"}', 'A', '2026-02-26 16:46:12', '2026-02-26 16:46:12'),
(2, 'ISAI(2-003', 'Which database language is used to retrieve data?', 0, NULL, '{\"A\": \"HTML\", \"B\": \"SQL\", \"C\": \"CSS\", \"D\": \"XML\"}', 'B', '2026-02-26 16:46:12', '2026-02-26 16:46:12'),
(3, 'ISAI(2-003', 'What is the primary purpose of a firewall?', 0, NULL, '{\"A\": \"Data backup\", \"B\": \"Power management\", \"C\": \"Network security filtering\", \"D\": \"CPU cooling\"}', 'C', '2026-02-26 16:46:12', '2026-02-26 16:46:12'),
(4, 'ISAI(2-003', 'Which HTTP method is typically used to update an existing resource?', 0, NULL, '{\"A\": \"GET\", \"B\": \"POST\", \"C\": \"PUT\", \"D\": \"TRACE\"}', 'C', '2026-02-26 16:46:12', '2026-02-26 16:46:12'),
(5, 'ISAI(2-003', 'Briefly explain the difference between authentication and authorization.', 1, 10, NULL, NULL, '2026-02-26 16:46:12', '2026-02-26 16:46:12'),
(12, 'AAI(4-005', '[Governance Core Series MCQ 1] Which practice best strengthens transparency in public transactions?', 0, NULL, '[\"Publishing clear reports and updates\", \"Keeping records internal only\", \"Avoiding stakeholder consultations\", \"Skipping documentation for speed\"]', 'Keeping records internal only', '2026-03-02 17:05:56', '2026-03-02 17:05:56'),
(13, 'AAI(4-005', '[Governance Core Series MCQ 2] What is the primary purpose of performance indicators in government programs?', 0, NULL, '[\"To measure outcomes and guide decisions\", \"To replace planning processes\", \"To remove accountability checks\", \"To limit public disclosure\"]', 'To measure outcomes and guide decisions', '2026-03-02 17:05:56', '2026-03-02 17:05:56'),
